INSERT INTO EDA_OUTLIER_RESULT ( outlier_id, eda_run_id, row_id, column_code, method_code_value_id, flag, reason ) SELECT EDA_OUTLIER_RESULT_SEQ.NEXTVAL, t.eda_run_id, t.row_id, t.column_code, t.method_code_value_id, t.flag, t.reason FROM (
SELECT #{row.edaRunId} AS eda_run_id, #{row.rowId} AS row_id, #{row.columnCode} AS column_code, #{row.methodCodeValueId} AS method_code_value_id, #{row.flag} AS flag, #{row.reason} AS reason FROM dual
) t
